cd /home/janfr && echo "=== koofr config.json keys (redacting values that look secret) ===" && uv run python - <<'PY'
import json, pathlib
p = pathlib.Path.home()/".koofr"/"config.json"
d = json.loads(p.read_text())
def redact(v):
    if isinstance(v, str) and len(v) > 24 and (' ' not in v):
        return f"<redacted {len(v)} chars>"
    return v
def walk(o, ind=0):
    if isinstance(o, dict):
        for k,v in o.items():
            if isinstance(v,(dict,list)):
                print("  "*ind+f"{k}:"); walk(v, ind+1)
            else:
                lk = k.lower()
                show = "<redacted>" if any(s in lk for s in ("token","pass","secret","auth","key","cookie")) else redact(v)
                print("  "*ind+f"{k}: {show}")
    elif isinstance(o, list):
        for i,v in enumerate(o):
            if isinstance(v,(dict,list)):
                print("  "*ind+f"[{i}]:"); walk(v, ind+1)
            else:
                print("  "*ind+f"[{i}]: {redact(v)}")
walk(d)
PY

